async function loadMedia(){let e=await fetch("../media/media.json"),i=await e.json(),t="";for(let o=0;o<i.length;o++){let a="",l="";"game"===i[o].type?(a="games",l="gamepad"):"book"===i[o].type?(a="books",l="book"):"film"===i[o].type?(a="films",l="video"):"show"===i[o].type?(a="shows",l="television"):(a="none",l="question-circle-o"),i[o].imbibed?a+=" imbibed":a+=" not-imbibed",i[o].favorite&&(a+=" favorites"),t+='<div class="col-lg-3 col-md-4 '+a+'"><div class="media-item"><div class="media-img"><span style="color: #008080;"><i class="icon-'+l+'"></i></span></div><div class="product-content text-center py-3"><h5 class="card-title">'+i[o].name+"</h5></div></div></div>"}document.getElementById("media-filter").innerHTML=t;var s=document.querySelector("#media-filter");iso=new Isotope(s,{itemSelector:".col-lg-3",layoutMode:"fitRows"})}